const clips = [];
for (const item of $input.all()) {
  if (item.json.error) continue;
  const videos = item.json.videos || [];
  for (const video of videos) {
    const files = video.video_files || [];
    const best = files.find(f => f.quality === 'hd' && f.file_type === 'video/mp4') || files.find(f => f.file_type === 'video/mp4') || files[0];
    if (best) clips.push({ url: best.link });
  }
}
if (clips.length === 0) {
  const pixabayKey = $env.PIXABAY_API_KEY;
  const splitKeywordItems = $("Split keywords").all();
  const fallbackKeyword = (splitKeywordItems[0] && splitKeywordItems[0].json && splitKeywordItems[0].json.keyword) || 'kids';
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://pixabay.com/api/videos/?key=${pixabayKey}&q=${encodeURIComponent(fallbackKeyword)}&per_page=6`,
      json: true,
    });
    for (const hit of (res.hits || [])) {
      const v = (hit.videos && (hit.videos.medium || hit.videos.large || hit.videos.small)) || null;
      if (v && v.url) clips.push({ url: v.url });
    }
  } catch (err) {
    // Pixabay fallback failed too; leave clips as-is (graceful degradation)
  }
}
return [{ json: { clips } }];

